+        private ByteBuffer getEntry(String name) throws IOException {
+            int offset = centralDirectoryOffset;
+            for (int i = 0; i < entryCount; ++i) {
+                if (readInt(offset) != CENTRAL_DIRECTORY_SIGNATURE) {
+                    throw new ZipException();
+                }
